import React, { useState } from 'react';
import './screentwo.css';

const ScreenTwo = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
  });

  const [errors, setErrors] = useState({
    name: false,
    email: false,
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));

    // Reset error state on change
    setErrors((prev) => ({ ...prev, [name]: false }));
  };

  const validateForm = () => {
    const newErrors = {
      name: formData.name.trim() === '',
      email: !/\S+@\S+\.\S+/.test(formData.email),
    };

    setErrors(newErrors);

    // Check if there are any errors
    return !Object.values(newErrors).some((error) => error);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validateForm()) {
      // Form is valid, proceed with submission logic
      console.log('Form submitted:', formData);
    }
  };

  return (
    <div id="screen2">
      <h1 className="title">Contact Us</h1>
      <p className="message">Please fill out the form below:</p>
      <form onSubmit={handleSubmit} noValidate>
        <div className="contact-details">
          <div>
            <label htmlFor="name">Name</label>
            <input
              type="text"
              id="name"
              name="name"
              value={formData.name}
              onChange={handleChange}
              className={errors.name ? 'invalid' : ''}
              placeholder="Enter your name"
            />
            {errors.name && (
              <span className="error-message visible">Name is required.</span>
            )}
          </div>
          <div>
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              className={errors.email ? 'invalid' : ''}
              placeholder="Enter your email"
            />
            {errors.email && (
              <span className="error-message visible">
                Please enter a valid email.
              </span>
            )}
          </div>
        </div>
        <div className="buttons">
          <button type="button" className="button-back">
            Back
          </button>
          <button type="submit" className="button-next">
            Submit
          </button>
        </div>
      </form>
    </div>
  );
};

export default ScreenTwo;
